What does the following program print?

```cpp
#include <iostream>

class Base {
public:
    void greet() const { std::cout << "Base\n"; }
};

class Derived : public Base {
public:
    void greet() const { std::cout << "Derived\n"; }
    void extra() const { std::cout << "Extra\n"; }
};

int main() {
    Derived d;
    Base* p = &d;
    p->greet();
}
```

What does the following program print?

```cpp
#include <iostream>

class Vehicle {
public:
    std::string type = "vehicle";
    void describe() const {
        std::cout << "I am a " << type << "\n";
    }
};

class Car : public Vehicle {
public:
    Car() { type = "car"; }
};

void print(const Vehicle& v) {
    v.describe();
}

int main() {
    Car c;
    print(c);
}
```

A developer writes this code expecting to print the dog's name, but gets a compile error. What is the bug?

```cpp
#include <iostream>

class Animal {
public:
    std::string name;
    Animal(std::string n) : name(n) {}
};

class Dog : public Animal {
public:
    Dog(std::string n) : Animal(n) {}
    void bark() const { std::cout << name << " says Woof!\n"; }
};

int main() {
    Animal a{"Rex"};
    Dog* dp = &a;
    dp->bark();
}
```
